import os
from cryptography.fernet import Fernet
from cryptography.hazmat.backends import default_backend
from cryptography.hazmat.primitives import serialization

# Load the encryption key from the application config
def load_key():
    with open("config.key", "rb") as key_file:
        return key_file.read()

# Encrypt the credit card number
def encrypt_credit_card(card_number):
    key = load_key()
    fernet = Fernet(key)
    encrypted_card = fernet.encrypt(card_number.encode())
    return encrypted_card

# Decrypt the credit card number
def decrypt_credit_card(encrypted_card):
    key = load_key()
    fernet = Fernet(key)
    decrypted_card = fernet.decrypt(encrypted_card).decode()
    return decrypted_card

# Example usage
if __name__ == "__main__":
    card_number = "4111111111111111"  # Example credit card number
    encrypted = encrypt_credit_card(card_number)
    print("Encrypted:", encrypted)
    decrypted = decrypt_credit_card(encrypted)
